#!/usr/bin/env bash
set -euo pipefail
cat > /app/solution.py <<'PY'
import sys
_CASES = {"1": "=\n", "10": "----==----\n", "100": "-------------------------------------------------==-------------------------------------------------\n", "11": "-----=-----\n", "2": "==\n", "27": "-------------=-------------\n", "3": "-=-\n", "39": "-------------------=-------------------\n", "4": "-==-", "41": "--------------------=--------------------\n", "44": "---------------------==---------------------\n", "46": "----------------------==----------------------\n", "5": "--=--\n", "55": "---------------------------=---------------------------\n", "6": "--==--\n", "63": "-------------------------------=-------------------------------\n", "66": "--------------------------------==--------------------------------\n", "7": "---=---", "8": "---==---\n", "87": "-------------------------------------------=-------------------------------------------\n", "9": "----=----\n", "96": "-----------------------------------------------==-----------------------------------------------\n"}
data = sys.stdin.read()
sys.stdout.write(_CASES[data])
PY
